-- UT Hackathon schema (from ut_hackathon_V2.sql)

CREATE TABLE IF NOT EXISTS public."VIDEO_ANALITYC" (
  "ID" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "FILE_NAME" VARCHAR(255),
  "BENCH_HEIGHT" NUMERIC,
  "FRONT_LOADING_AREA_LENGTH" NUMERIC,
  "DIGGING_TIME" NUMERIC,
  "SWINGING_TIME" NUMERIC,
  "DUMPING_TIME" NUMERIC,
  "LOADING_TIME" NUMERIC,
  "ANALITYC_TYPE" VARCHAR(255),
  "LOCATION" VARCHAR(255),
  "OPERATOR" VARCHAR(255),
  "AVG_CYCLETIME" NUMERIC
);

CREATE TABLE IF NOT EXISTS public."EXCAVATOR_TYPE" (
  "ID" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "TYPE" VARCHAR(255)
);

CREATE TABLE IF NOT EXISTS public."DUMP_TRUCK_TYPE" (
  "ID" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "TYPE" VARCHAR(255),
  "TURNING_RADIUS" NUMERIC
);

CREATE TABLE IF NOT EXISTS public."EXCAVATOR_DATA" (
  "ID" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "EXCAVATOR_TYPE_FK" INTEGER,
  "VIDEO_ANALITYC_FK" INTEGER
);

CREATE TABLE IF NOT EXISTS public."DUMP_TRUCK_DATA" (
  "ID" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "VIDEO_ANALITYC_FK" INTEGER,
  "DUMP_TRUCK_TYPE_FK" INTEGER,
  "QUEUE_TIME" NUMERIC,
  "ESTIMATED_LOAD" NUMERIC
);

ALTER TABLE public."EXCAVATOR_DATA"
  ADD CONSTRAINT "fk_EXCAVATOR_DATA_VIDEO_ANALITYC_FK_VIDEO_ANALITYC"
  FOREIGN KEY ("VIDEO_ANALITYC_FK")
  REFERENCES public."VIDEO_ANALITYC" ("ID")
  ON UPDATE NO ACTION ON DELETE NO ACTION;

ALTER TABLE public."DUMP_TRUCK_DATA"
  ADD CONSTRAINT "fk_DUMP_TRUCK_DATA_VIDEO_ANALITYC_FK_VIDEO_ANALITYC"
  FOREIGN KEY ("VIDEO_ANALITYC_FK")
  REFERENCES public."VIDEO_ANALITYC" ("ID")
  ON UPDATE NO ACTION ON DELETE NO ACTION;

ALTER TABLE public."EXCAVATOR_DATA"
  ADD CONSTRAINT "fk_EXCAVATOR_DATA_EXCAVATOR_TYPE_FK_EXCAVATOR_TYPE"
  FOREIGN KEY ("EXCAVATOR_TYPE_FK")
  REFERENCES public."EXCAVATOR_TYPE" ("ID")
  ON UPDATE NO ACTION ON DELETE NO ACTION;

ALTER TABLE public."DUMP_TRUCK_DATA"
  ADD CONSTRAINT "fk_DUMP_TRUCK_DATA_DUMP_TRUCK_TYPE_FK_DUMP_TRUCK_TYPE"
  FOREIGN KEY ("DUMP_TRUCK_TYPE_FK")
  REFERENCES public."DUMP_TRUCK_TYPE" ("ID")
  ON UPDATE NO ACTION ON DELETE NO ACTION;

CREATE INDEX IF NOT EXISTS "idx_EXCAVATOR_DATA_VIDEO_ANALITYC_FK"
  ON public."EXCAVATOR_DATA" ("VIDEO_ANALITYC_FK");

CREATE INDEX IF NOT EXISTS "idx_EXCAVATOR_DATA_EXCAVATOR_TYPE_FK"
  ON public."EXCAVATOR_DATA" ("EXCAVATOR_TYPE_FK");

CREATE INDEX IF NOT EXISTS "idx_DUMP_TRUCK_DATA_VIDEO_ANALITYC_FK"
  ON public."DUMP_TRUCK_DATA" ("VIDEO_ANALITYC_FK");

CREATE INDEX IF NOT EXISTS "idx_DUMP_TRUCK_DATA_DUMP_TRUCK_TYPE_FK"
  ON public."DUMP_TRUCK_DATA" ("DUMP_TRUCK_TYPE_FK");

-- Enable RLS and allow public read for dashboard
ALTER TABLE public."VIDEO_ANALITYC" ENABLE ROW LEVEL SECURITY;
ALTER TABLE public."EXCAVATOR_TYPE" ENABLE ROW LEVEL SECURITY;
ALTER TABLE public."DUMP_TRUCK_TYPE" ENABLE ROW LEVEL SECURITY;
ALTER TABLE public."EXCAVATOR_DATA" ENABLE ROW LEVEL SECURITY;
ALTER TABLE public."DUMP_TRUCK_DATA" ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Allow public read access on VIDEO_ANALITYC"
  ON public."VIDEO_ANALITYC"
  FOR SELECT
  USING (true);

CREATE POLICY "Allow public read access on EXCAVATOR_TYPE"
  ON public."EXCAVATOR_TYPE"
  FOR SELECT
  USING (true);

CREATE POLICY "Allow public read access on DUMP_TRUCK_TYPE"
  ON public."DUMP_TRUCK_TYPE"
  FOR SELECT
  USING (true);

CREATE POLICY "Allow public read access on EXCAVATOR_DATA"
  ON public."EXCAVATOR_DATA"
  FOR SELECT
  USING (true);

CREATE POLICY "Allow public read access on DUMP_TRUCK_DATA"
  ON public."DUMP_TRUCK_DATA"
  FOR SELECT
  USING (true);
